<?php
if (session_status() === PHP_SESSION_NONE) session_start();
require_once __DIR__ . '/../../config/db.php';
require_once __DIR__ . '/../../core/_activity_viewer_template.php';
header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
header('Pragma: no-cache');
header('Expires: 0');

$activityId = isset($_GET['id']) ? trim((string)$_GET['id']) : '';
$mode = isset($_GET['mode']) ? trim((string)$_GET['mode']) : '';
$returnTo = isset($_GET['return_to']) ? trim((string)$_GET['return_to']) : '';
$source = isset($_GET['source']) ? trim((string)$_GET['source']) : '';
$isEditorAuth = !empty($_SESSION['admin_logged']) || !empty($_SESSION['academic_logged']) || !empty($_SESSION['teacher_logged']) || !empty($_SESSION['teacher_id']) || !empty($_SESSION['teacher_username']) || !empty($_SESSION['academic_id']) || !empty($_SESSION['admin_id']);
$isCreatorSource = in_array(strtolower($source), ['creator','create','editor','teacher'], true);
if ($mode === 'edit' && !$isEditorAuth && !$isCreatorSource) { header('Location: /lessons/lessons/academic/login.php'); exit; }
$allowEditor = ($mode === 'edit' || $isCreatorSource) && ($isEditorAuth || $isCreatorSource);

$defaults = [
 'title'=>'Free Conversation','topic'=>'Talk about your favorite food.','level'=>'B1','duration_min'=>8,'conversation_mode'=>'chat_feedback','difficulty'=>'intermediate','agentName'=>'Alex','persona'=>'Friendly coach','teacherVoiceId'=>'nzFihrBIvB34imQBuxub','system_prompt'=>'Have a friendly open conversation. Ask short follow-up questions.','targetVocab'=>[['word'=>'order','meaning'=>'ask for food'],['word'=>'delicious','meaning'=>'very tasty'],['word'=>'recommend','meaning'=>'suggest']], 'hints'=>['Give a complete answer.','Ask a follow-up question.','Try using a target word.'],'targetLanguage'=>'English','showFeedback'=>true,'showVocab'=>true,'showCoachTips'=>true,'allowHints'=>true,'scoringWeights'=>['fluency'=>40,'grammar'=>35,'vocabulary'=>25]
];
$savedData = [];
try {
 if ($activityId !== '') {
  $stmt = $pdo->prepare('SELECT data FROM activities WHERE id = :id LIMIT 1');
  $stmt->execute(['id'=>$activityId]);
  $row = $stmt->fetch(PDO::FETCH_ASSOC);
  if ($row && !empty($row['data'])) { $parsed = json_decode((string)$row['data'], true); if (is_array($parsed)) $savedData = $parsed; }
 }
} catch (Throwable $e) { error_log('[free_conversation/viewer] load error: '.$e->getMessage()); }
$payload = array_replace_recursive($defaults, $savedData);
$viewerTitle = trim((string)($payload['title'] ?? '')) !== '' ? (string)$payload['title'] : 'Free Conversation';
ob_start();
?>
