:#7f77dd;font-weight:900;font-size:13px;padding:6px 12px;border-radius:999px;flex:0 0 auto}.fc-chat{background:#f7f4ff;background-image:radial-gradient(#ede9fa 1.5px,transparent 1.5px);background-size:22px 22px;display:flex;flex-direction:column}.fc-row{margin-bottom:4px}.fc-ai .fc-bubble{border-radius:4px 18px 18px 18px;box-shadow:0 2px 6px rgba(127,119,221,.08)}.fc-me .fc-bubble{border-radius:18px 4px 18px 18px;box-shadow:0 2px 6px rgba(249,115,22,.08)}.fc-msg{max-width:80%;display:flex;flex-direction:column}.fc-me .fc-msg{margin-left:auto;align-items:flex-end}.fc-time{font-size:10px;font-weight:800;color:#b4acd6;margin-top:4px;padding:0 4px}.fc-me .fc-time{text-align:right;color:#e0a373}.fc-typing{display:inline-flex;gap:5px;align-items:center;padding:14px 16px}.fc-typing span{width:7px;height:7px;border-radius:50%;background:#9b8fcc;display:inline-block;animation:fc-blink 1.2s infinite ease-in-out}.fc-typing span:nth-child(2){animation-delay:.2s}.fc-typing span:nth-child(3){animation-delay:.4s}@keyframes fc-blink{0%,80%,100%{opacity:.3;transform:translateY(0)}40%{opacity:1;transform:translateY(-3px)}}.fc-score-grid{display:flex;gap:10px;flex-wrap:wrap;justify-content:center;margin:16px 0}.fc-score-grid .fc-chip{min-width:88px}
