window.FC_ACTIVITY_ID=<?= json_encode($activityId, JSON_HEX_TAG|JSON_HEX_APOS|JSON_HEX_QUOT|JSON_HEX_AMP) ?>;window.FC_RETURN_TO=<?= json_encode($returnTo, JSON_HEX_TAG|JSON_HEX_APOS|JSON_HEX_QUOT|JSON_HEX_AMP) ?>;window.FC_PAYLOAD=<?= json_encode($payload, JSON_HEX_TAG|JSON_HEX_APOS|JSON_HEX_QUOT|JSON_HEX_AMP) ?>;window.FC_ALLOW_EDITOR=<?= json_encode($allowEditor) ?>;
(function(){
const root=document.getElementById('fc-root');let cfg=norm(window.FC_PAYLOAD||{}),view=window.FC_ALLOW_EDITOR?'editor':'chat',msgs=[],input='',remaining=seconds(),started=false,ended=false,busy=false,status='',results=[],tip='Try to answer with a complete sentence.';let timer=null,rec=null,micActive=false,manualMicStop=false,restartPending=false,speechPrefix='',confirmedSpeech='',interimSpeech='';
function h(v){return String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}function norm(p){let vocab=Array.isArray(p.targetVocab)?p.targetVocab:[];vocab=vocab.map(x=>typeof x==='string'?{word:x,meaning:''}:{word:String(x.word||x.term||''),meaning:String(x.meaning||x.definition||'')}).filter(x=>x.word);return{title:String(p.title||'Free Conversation'),topic:String(p.topic||'Open Topic'),level:String(p.level||p.difficulty||'B1'),duration_min:Number(p.duration_min??p.timeLimit??8),conversation_mode:String(p.conversation_mode||'chat_feedback'),difficulty:String(p.difficulty||'intermediate'),agentName:String(p.agentName||'Alex'),persona:String(p.persona||'Friendly coach'),teacherVoiceId:String(p.teacherVoiceId||'nzFihrBIvB34imQBuxub'),system_prompt:String(p.system_prompt||'Have a friendly open conversation. Ask short follow-up questions.'),targetVocab:vocab,hints:Array.isArray(p.hints)?p.hints:['Give a complete answer.'],targetLanguage:String(p.targetLanguage||'English'),showFeedback:p.showFeedback!==false,showVocab:p.showVocab!==false,showCoachTips:p.showCoachTips!==false,allowHints:p.allowHints!==false,scoringWeights:Object.assign({fluency:40,grammar:35,vocabulary:25},p.scoringWeights||{})}}function seconds(){return cfg.duration_min>0?cfg.duration_min*60:0}function fmt(s){if(cfg.duration_min<=0)return '∞';let m=Math.floor(s/60);return m+':'+String(s%60).padStart(2,'0')}function vocabWords(){return cfg.targetVocab.map(v=>v.word)}function usedWords(){let text=msgs.filter(m=>m.role==='student').map(m=>m.text).join(' ').toLowerCase();return new Set(vocabWords().filter(w=>text.includes(String(w).toLowerCase())))}function words(s){return String(s||'').toLowerCase().replace(/[^a-z0-9\s]/g,' ').split(/\s+/).filter(w=>w.length>1)}function localScore(txt){let trimmed=txt.trim(),wc=trimmed?trimmed.split(/\s+/).length:0,used=usedWords(),target=vocabWords().length,vu=target?Math.round(used.size/target*100):70,flu=wc?Math.min(100,55+wc*6):0,grammar=/\b(i|you|we|they|he|she|it)\b/i.test(txt)?80:65;let weights=cfg.scoringWeights,total=Math.round((flu*weights.fluency+grammar*weights.grammar+vu*weights.vocabulary)/100);return{fluency:Math.min(100,flu),grammar:grammar,vocabulary:Math.min(100,vu),total:total,corrected:txt,praise:'Good effort speaking about the topic.',tips:['Use complete sentences.','Try one target vocabulary word.']}}
function startTimer(){if(started)return;started=true;if(cfg.duration_min>0){timer=setInterval(()=>{remaining--;if(remaining<=0){clearInterval(timer);finish()}else render()},1000)}}function header(){return '<div class="fc-top"><div class="fc-contact"><div class="fc-contact-avatar">🤖</div><div class="fc-contact-info"><div class="fc-contact-name">'+h(cfg.agentName)+'</div><div class="fc-contact-status">'+h(cfg.topic)+' · Level '+h(cfg.level)+'</div></div><div class="fc-contact-timer">'+fmt(remaining)+'</div></div></div>'}
function fmtTime(ts){let d=ts?new Date(ts):new Date();return String(d.getHours()).padStart(2,'0')+':'+String(d.getMinutes()).padStart(2,'0')}
function chat(){let used=usedWords();return '<div class="fc-app">'+header()+'<div class="fc-main"><main class="fc-chat">'+(msgs.length?msgs.map(message).join(''):'<div class="fc-panel"><div class="fc-mini">Coach</div>Start the conversation. Use your voice or type your first answer.</div>')+(busy?typingBubble():'')+'</main><aside class="fc-side">'+(cfg.showVocab?'<div class="fc-panel"><div class="fc-mini">Vocabulary tracker</div><div class="fc-vocab">'+cfg.targetVocab.map(v=>'<span class="fc-word '+(used.has(v.word)?'used':'')+'">'+h(v.word)+'</span>').join('')+'</div></div>':'')+(cfg.showCoachTips?'<div class="fc-panel"><div class="fc-mini">Coach tips</div><div class="fc-tip">'+h(tip)+'</div>'+(cfg.allowHints?'<button type="button" class="fc-btn" data-action="hint" style="margin-top:10px;width:100%">Give me a hint</button>':'')+'</div>':'')+'</aside></div><div class="fc-inputbar"><button type="button" class="fc-btn '+(micActive?'listening':'')+'" data-action="mic">'+(micActive?'⏹ Stop recording':'🎙 Speak')+'</button><input class="fc-input" data-input="1" value="'+h(input)+'" placeholder="Speak freely. Tap Stop recording when finished..."><button type="button" class="fc-btn fc-primary" data-action="send" '+(busy?'disabled':'')+'>'+(busy?'Thinking...':'Send')+'</button><button type="button" class="fc-btn" data-action="finish">Finish</button></div></div>'}
function typingBubble(){return '<div class="fc-row fc-ai"><div class="fc-avatar">🤖</div><div class="fc-bubble fc-typing"><span></span><span></span><span></span></div></div>'}
function message(m,i){let mine=m.role==='student';return '<div class="fc-row '+(mine?'fc-me':'fc-ai')+'">'+(!mine?'<div class="fc-avatar">🤖</div>':'')+'<div class="fc-msg"><div class="fc-bubble">'+h(m.text)+'</div><div class="fc-time">'+fmtTime(m.time)+(mine?' ✓✓':'')+'</div></div>'+(mine?'<div class="fc-avatar">🙂</div>':'')+'</div>'}
async function send(){let text=input.trim();if(!text)return;stopMic(true);resetSpeechState();startTimer();input='';let fb=localScore(text);msgs.push({role:'student',text:text,feedback:fb,time:Date.now()});results.push(fb);busy=true;render();try{let history=msgs.filter(m=>m.role!=='student_feedback').slice(-8).map(m=>({role:m.role==='ai'?'assistant':'user',content:m.text}));let system=cfg.system_prompt+'\nTopic: '+cfg.topic+'\nPersona: '+cfg.persona+'\nLevel: '+cfg.level+'\nReply in '+cfg.targetLanguage+'. Keep it short and ask one follow-up question.';let resp=await fetch('claude_proxy.php',{method:'POST',headers:{'Content-Type':'application/json'},credentials:'same-origin',body:JSON.stringify({model:'claude-sonnet-4-5',max_tokens:500,system:system,messages:history})});if(!resp.ok)throw new Error('HTTP '+resp.status);let data=await resp.json();let raw=String((data.content&&data.content[0]&&data.content[0].text)||'');let ai=raw;try{let j=JSON.parse(raw);ai=j.response||raw;if(j.feedback)Object.assign(fb,j.feedback)}catch(e){}let aiText=ai||'Tell me more about that.';msgs.push({role:'ai',text:aiText,time:Date.now()});tip=(fb.tips&&fb.tips[0])||'Try to add more details.';playAiAudio(aiText);}catch(err){msgs.push({role:'ai',text:'Great! Tell me a little more about '+cfg.topic+'.',time:Date.now()});tip='I could not reach the AI, but you can keep practicing.'}finally{busy=false;render();scrollDown()}}
function scrollDown(){setTimeout(()=>{let c=root.querySelector('.fc-chat');if(c)c.scrollTop=c.scrollHeight},40)}async function playAiAudio(text){try{let fd=new FormData();fd.append('text',text);fd.append('voice_id',cfg.teacherVoiceId||'nzFihrBIvB34imQBuxub');let resp=await fetch('tts.php',{method:'POST',body:fd,credentials:'same-origin'});if(!resp.ok)return;let blob=await resp.blob();let url=URL.createObjectURL(blob);let audio=new Audio(url);audio.onended=()=>URL.revokeObjectURL(url);audio.play().catch(()=>{})}catch(e){}}function avgOf(key){return results.length?Math.round(results.reduce((a,r)=>a+(Number(r[key])||0),0)/results.length):0}function buildSaveUrl(percent){if(!window.FC_RETURN_TO||!window.FC_ACTIVITY_ID)return '';let sep=window.FC_RETURN_TO.indexOf('?')!==-1?'&':'?';return window.FC_RETURN_TO+sep+'activity_percent='+encodeURIComponent(String(percent))+'&activity_errors='+encodeURIComponent(String(100-percent))+'&activity_total=100&activity_id='+encodeURIComponent(String(window.FC_ACTIVITY_ID))+'&activity_type=free_conversation'}function persistScoreSilently(url){if(!url)return Promise.resolve(false);return fetch(url,{method:'GET',credentials:'same-origin',cache:'no-store'}).then(r=>!!(r&&r.ok)).catch(()=>false)}function navigateToReturn(url){if(!url)return;try{if(window.top&&window.top!==window.self){window.top.location.href=url;return}}catch(e){}window.location.href=url}async function persistFinalScore(){let percent=avgOf('total');let saveUrl=buildSaveUrl(percent);if(!saveUrl)return;let ok=await persistScoreSilently(saveUrl);if(!ok)navigateToReturn(saveUrl)}function finish(){if(ended)return;stopMic(true);resetSpeechState();ended=true;view='complete';if(timer)clearInterval(timer);render();persistFinalScore()}function complete(){let avg=avgOf('total'),avgFluency=avgOf('fluency'),avgGrammar=avgOf('grammar'),avgVocab=avgOf('vocabulary');return '<div class="fc-app">'+header()+'<div class="fc-complete"><div class="fc-complete-card"><div class="fc-score-ring" style="--p:'+avg+'%"><span>'+avg+'%</span></div><h1 style="font-family:Fredoka,sans-serif;color:#f97316">Conversation Complete!</h1><p style="font-weight:900;color:#7f77dd;margin:12px 0 4px">Turns: '+results.length+' · Target words used: '+usedWords().size+'/'+vocabWords().length+'</p><div class="fc-score-grid"><div class="fc-chip"><b>'+avgFluency+'</b><span>Fluency</span></div><div class="fc-chip"><b>'+avgGrammar+'</b><span>Grammar</span></div><div class="fc-chip"><b>'+avgVocab+'</b><span>Vocabulary</span></div><div class="fc-chip"><b>'+avg+'</b><span>Total</span></div></div><button type="button" class="fc-btn fc-primary" data-action="restart">Try again</button></div></div></div>'}
function editor(){return '<div class="fc-app"><div class="fc-top"><div class="fc-title">Free Conversation Editor</div></div><div class="fc-editor"><div class="fc-wrap"><section class="fc-card"><div class="fc-head">General settings</div><div class="fc-body"><div class="fc-grid2"><div><label class="fc-label">Activity title</label><input class="fc-field" data-cfg="title" value="'+h(cfg.title)+'"></div><div><label class="fc-label">Topic</label><input class="fc-field" data-cfg="topic" value="'+h(cfg.topic)+'"></div></div><div class="fc-grid3" style="margin-top:14px"><div><label class="fc-label">CEFR Level</label><select class="fc-select" data-cfg="level">'+['A2','B1','B2','C1'].map(x=>'<option '+(cfg.level===x?'selected':'')+'>'+x+'</option>').join('')+'</select></div><div><label class="fc-label">Duration</label><select class="fc-select" data-cfg="duration_min">'+[[5,'5 minutes'],[8,'8 minutes'],[10,'10 minutes'],[15,'15 minutes'],[0,'No limit']].map(a=>'<option value="'+a[0]+'" '+(Number(cfg.duration_min)===a[0]?'selected':'')+'>'+a[1]+'</option>').join('')+'</select></div><div><label class="fc-label">AI Persona</label><select class="fc-select" data-cfg="persona">'+['Friendly coach','Curious friend','Interviewer','Debate partner'].map(x=>'<option '+(cfg.persona===x?'selected':'')+'>'+x+'</option>').join('')+'</select></div></div><div class="fc-grid2" style="margin-top:14px"><div><label class="fc-label">Agent name</label><input class="fc-field" data-cfg="agentName" value="'+h(cfg.agentName)+'"></div><div><label class="fc-label">AI voice</label><select class="fc-select" data-cfg="teacherVoiceId"><option value="nzFihrBIvB34imQBuxub"'+(cfg.teacherVoiceId==="nzFihrBIvB34imQBuxub"?" selected":"")+'>Adult Male (Josh)</option><option value="NoOVOzCQFLOvtsMoNcdT"'+(cfg.teacherVoiceId==="NoOVOzCQFLOvtsMoNcdT"?" selected":"")+'>Adult Female (Lily)</option><option value="Nggzl2QAXh3OijoXD116"'+(cfg.teacherVoiceId==="Nggzl2QAXh3OijoXD116"?" selected":"")+'>Child (Candy)</option></select></div></div><label class="fc-label" style="margin-top:14px">AI system prompt / scenario</label><textarea class="fc-textarea" data-cfg="system_prompt">'+h(cfg.system_prompt)+'</textarea></div></section><section class="fc-card"><div class="fc-head">Target vocabulary pairs</div><div class="fc-body"><div id="fc-vocab-editor">'+cfg.targetVocab.map((v,i)=>'<div class="fc-vrow"><input class="fc-field" data-vocab="'+i+'" data-prop="word" value="'+h(v.word)+'" placeholder="word"><input class="fc-field" data-vocab="'+i+'" data-prop="meaning" value="'+h(v.meaning)+'" placeholder="meaning"><button type="button" class="fc-btn" data-action="remove-vocab" data-index="'+i+'">Remove</button></div>').join('')+'</div><button type="button" class="fc-btn" data-action="add-vocab">+ Add vocabulary pair</button></div></section><section class="fc-card"><div class="fc-head">Feedback and scoring</div><div class="fc-body"><div class="fc-grid2">'+['showFeedback:Show feedback','showVocab:Show vocab tracker','showCoachTips:Show coach tips','allowHints:Allow hints'].map(s=>{let p=s.split(':');return '<label class="fc-toggle"><input type="checkbox" data-toggle="'+p[0]+'" '+(cfg[p[0]]?'checked':'')+'> '+p[1]+'</label>'}).join('')+'</div><div style="margin-top:18px">'+['fluency','grammar','vocabulary'].map(k=>'<div class="fc-slider"><b>'+k+'</b><input type="range" min="0" max="100" data-weight="'+k+'" value="'+h(cfg.scoringWeights[k])+'"><span>'+h(cfg.scoringWeights[k])+'%</span></div>').join('')+'</div></div></section><div class="fc-savebar"><button type="button" class="fc-btn" data-action="preview">Preview as student</button><div class="fc-status">'+h(status)+'</div><button type="button" class="fc-btn fc-primary" data-action="save">Save activity</button></div></div></div></div>'}
function render(){if(!root)return;let sc=root.querySelector('.fc-chat')||root.querySelector('.fc-editor,.fc-side,.fc-main'),top=sc?sc.scrollTop:0;root.innerHTML=view==='editor'?editor():(view==='complete'?complete():chat());let sc2=root.querySelector('.fc-chat')||root.querySelector('.fc-editor,.fc-side,.fc-main');if(sc2)sc2.scrollTop=top}function setMicButton(){let btn=root.querySelector('[data-action="mic"]');if(btn){btn.classList.toggle('listening',micActive);btn.textContent=micActive?'⏹ Stop recording':'🎙 Speak'}}function resetSpeechState(){speechPrefix='';confirmedSpeech='';interimSpeech='';restartPending=false}
function updateInputDisplay(){input=[speechPrefix,confirmedSpeech,interimSpeech].filter(Boolean).join(' ').replace(/\s+/g,' ').trim();let box=root.querySelector('[data-input]');if(box)box.value=input}
function commitConfirmedSession(){let committed=[speechPrefix,confirmedSpeech].filter(Boolean).join(' ').replace(/\s+/g,' ').trim();speechPrefix=committed;confirmedSpeech='';interimSpeech='';input=speechPrefix}
function mergeSpeechParts(parts){let merged='';for(let part of parts){part=String(part||'').replace(/\s+/g,' ').trim();if(!part)continue;if(!merged){merged=part;continue}let a=merged.toLowerCase().split(' '),b=part.toLowerCase().split(' '),overlap=0,max=Math.min(a.length,b.length);for(let n=max;n>0;n--){if(a.slice(-n).join(' ')===b.slice(0,n).join(' ')){overlap=n;break}}if(overlap===b.length)continue;if(overlap>0)merged+=' '+part.split(' ').slice(overlap).join(' ');else if(part.toLowerCase().startsWith(merged.toLowerCase()+' '))merged=part;else if(merged.toLowerCase().startsWith(part.toLowerCase()+' '))continue;else merged+=' '+part}return merged.replace(/\s+/g,' ').trim()}
function attachRecognition(r){r.lang='en-US';r.continuous=true;r.interimResults=true;r.maxAlternatives=1;r.onresult=e=>{let finals=[],interims=[];for(let i=0;i<e.results.length;i++){let transcript=String(e.results[i][0].transcript||'').trim();if(!transcript)continue;if(e.results[i].isFinal)finals.push(transcript);else interims.push(transcript)}confirmedSpeech=mergeSpeechParts(finals);interimSpeech=mergeSpeechParts(interims);if(confirmedSpeech&&interimSpeech){let c=confirmedSpeech.toLowerCase(),v=interimSpeech.toLowerCase();if(v===c||c.endsWith(' '+v)||c===v)interimSpeech='';else if(v.startsWith(c+' '))interimSpeech=interimSpeech.slice(confirmedSpeech.length).trim()}updateInputDisplay()};r.onerror=e=>{if(e.error==='no-speech'||e.error==='aborted'){scheduleRecognitionRestart();return}if(e.error==='not-allowed'){manualMicStop=true;micActive=false;setMicButton();alert('Microphone access was blocked. Please allow microphone access to use voice input.');return}micActive=false;setMicButton()};r.onend=()=>{if(micActive&&!manualMicStop){scheduleRecognitionRestart()}else{micActive=false;setMicButton()}}}
function startRecognitionSession(){let SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR){micActive=false;setMicButton();return}commitConfirmedSession();rec=new SR();attachRecognition(rec);try{rec.start()}catch(e){micActive=false;setMicButton()}}
function scheduleRecognitionRestart(){if(!micActive||manualMicStop||restartPending)return;restartPending=true;setTimeout(()=>{restartPending=false;if(!micActive||manualMicStop)return;startRecognitionSession()},350)}
function stopMic(manual){manualMicStop=!!manual;micActive=false;if(manual){interimSpeech='';input=[speechPrefix,confirmedSpeech].filter(Boolean).join(' ').replace(/\s+/g,' ').trim();let box=root.querySelector('[data-input]');if(box)box.value=input}try{if(rec)rec.stop()}catch(e){}setMicButton()}
function mic(){if(micActive){stopMic(true);return}let SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR){alert('Speech recognition is not supported. You can type your answer.');return}manualMicStop=false;restartPending=false;speechPrefix=input?input.trim():'';confirmedSpeech='';interimSpeech='';rec=new SR();attachRecognition(rec);try{rec.start();micActive=true;setMicButton()}catch(e){micActive=false;setMicButton();alert('Could not start the microphone. Please allow microphone access.')}}
root.addEventListener('input',e=>{let el=e.target;if(el.dataset.input){input=el.value;return}if(el.dataset.cfg){cfg[el.dataset.cfg]=el.dataset.cfg==='duration_min'?Number(el.value):el.value;return}if(el.dataset.toggle){cfg[el.dataset.toggle]=el.checked;return}if(el.dataset.weight){cfg.scoringWeights[el.dataset.weight]=Number(el.value);el.nextElementSibling.textContent=el.value+'%';return}if(el.dataset.vocab){let i=Number(el.dataset.vocab);cfg.targetVocab[i]=Object.assign({word:'',meaning:''},cfg.targetVocab[i]);cfg.targetVocab[i][el.dataset.prop]=el.value;return}});root.addEventListener('change',e=>{let el=e.target;if(el.dataset.cfg){cfg[el.dataset.cfg]=el.dataset.cfg==='duration_min'?Number(el.value):el.value}});root.addEventListener('keydown',e=>{if(e.target&&e.target.dataset.input&&e.key==='Enter'){e.preventDefault();send()}});root.addEventListener('click',async e=>{let b=e.target.closest('[data-action]');if(!b)return;e.preventDefault();let a=b.dataset.action;if(a==='send')send();if(a==='mic')mic();if(a==='finish')finish();if(a==='restart'){stopMic(true);resetSpeechState();msgs=[];results=[];input='';remaining=seconds();started=false;ended=false;view='chat';render()}if(a==='hint'){tip=cfg.hints[Math.floor(Math.random()*cfg.hints.length)]||'Add one more detail.';render()}if(a==='preview'){stopMic(true);resetSpeechState();view='chat';msgs=[];results=[];input='';remaining=seconds();started=false;render()}if(a==='add-vocab'){cfg.targetVocab.push({word:'',meaning:''});render()}if(a==='remove-vocab'){cfg.targetVocab.splice(Number(b.dataset.index),1);render()}if(a==='save'){if(!window.FC_ACTIVITY_ID){status='No activity ID';render();return}status='Saving...';render();try{let body=Object.assign({},cfg,{id:window.FC_ACTIVITY_ID,timeLimit:cfg.duration_min,difficulty:cfg.level==='A2'?'beginner':(cfg.level==='C1'?'advanced':'intermediate')});let resp=await fetch('save.php',{method:'POST',headers:{'Content-Type':'application/json'},credentials:'same-origin',body:JSON.stringify(body)});let json=await resp.json().catch(()=>({}));if(!resp.ok||json.error)throw new Error(json.error||('HTTP '+resp.status));status='Saved successfully'}catch(err){status='Could not save: '+err.message}finally{render()}}});try{render()}catch(err){console.error('[free conversation] render error',err);root.innerHTML='<div style="padding:20px">Free Conversation could not render. Check console.</div>'}
})();
</script>
